#include <stdio.h>

int main(){
    int T;
    if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int n; scanf("%d",&n);
        int arr[101];
        for(int i=0;i<n;++i) scanf("%d",&arr[i]);
        int *ptr = arr;
        for(int i=0;i<n;++i) printf("%d\n", *(ptr+i));
    }
    return 0;
}

