import sys

def main():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        n = int(next(it))
        for _ in range(n):
            out.append(next(it).decode())
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

